const description = $('Extract Description').item.json.description ?? 'No description';
const timeline = $('Extract Timeline').item.json.timeline ?? 'No timeline';
const risks = $('Extract Risks').item.json.risks ?? 'No risks';
const taskboard = $('Extract Task Board').item.json.taskboard ?? 'No task board';
const chatInput = $('When chat message received').item.json.chatInput;

// ── Task count calculation (deterministic — do not let LLM recount) ──
const rawData = taskboard;

// Handle both real newlines AND escaped \n
const rows = rawData
  .split(/\\n|\n/)
  .map(line => line.trim())
  .filter(line => line !== '');

// Skip header row
const dataRows = rows.slice(1);

const counts = { Done: 0, 'In Progress': 0, 'To Do': 0, Blocked: 0 };
const byStatus = { Done: [], 'In Progress': [], 'To Do': [], Blocked: [] };

dataRows.forEach(row => {
  // Handle both tab and comma separators
  const cols = row.includes('\t') ? row.split('\t') : row.split(',');
  const taskId = cols[0]?.trim();
  const status = cols[2]?.trim();
  if (counts.hasOwnProperty(status)) {
    counts[status]++;
    byStatus[status].push(taskId);
  }
});

const total = counts['Done'] + counts['In Progress'] 
            + counts['Blocked'] + counts['To Do'];

const taskSummary = `TASK COUNT SUMMARY (pre-computed — use these exact numbers, do not recount):
- Done: ${counts['Done']} tasks — ${byStatus['Done'].join(', ')}
- In Progress: ${counts['In Progress']} tasks — ${byStatus['In Progress'].join(', ')}
- Blocked: ${counts['Blocked']} tasks — ${byStatus['Blocked'].join(', ')}
- To Do: ${counts['To Do']} tasks — ${byStatus['To Do'].join(', ')}
- Total: ${total} tasks
DO NOT recount. Use these numbers exactly as written above.`;

// ── Return all data including pre-computed task summary ──
return [{ json: { 
  description: description, 
  timeline: timeline, 
  risks: risks, 
  taskboard: taskboard, 
  taskSummary: taskSummary,
  chatInput: chatInput 
} }];
